def gen(rng, size):
    n = max(1, size)
    # First value must be a real node; rest may be null to vary shape.
    arr = [rng.randint(0, 1)]
    for _ in range(n - 1):
        if rng.random() < 0.25:
            arr.append(None)
        else:
            arr.append(rng.randint(0, 1))
    return [arr]

