class Solution:
    def pruneTree(self, root):
        # Independent: explicitly test whether a subtree contains any 1, then
        # rebuild only the surviving structure.
        def contains_one(node):
            if not node:
                return False
            return node.val == 1 or contains_one(node.left) or contains_one(node.right)
        def build(node):
            if not node or not contains_one(node):
                return None
            node.left = build(node.left)
            node.right = build(node.right)
            return node
        return build(root)

